from flask import Flask, render_template, redirect, url_for, request
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Helper functions to load data

def load_memberships():
    filename = os.path.join(DATA_DIR, 'memberships.txt')
    memberships = []
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 6:
                    membership_id = int(parts[0])
                    plan_name = parts[1]
                    price = float(parts[2])
                    billing_cycle = parts[3]
                    features = parts[4].split(', ')
                    max_classes = parts[5]
                    if max_classes.isdigit():
                        max_classes = int(max_classes)
                    memberships.append({
                        'membership_id': membership_id,
                        'plan_name': plan_name,
                        'price': price,
                        'billing_cycle': billing_cycle,
                        'features': features,
                        'max_classes': max_classes
                    })
    except FileNotFoundError:
        pass
    return memberships


def load_classes():
    filename = os.path.join(DATA_DIR, 'classes.txt')
    classes = []
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 8:
                    class_id = int(parts[0])
                    class_name = parts[1]
                    trainer_id = int(parts[2])
                    class_type = parts[3]
                    schedule_day = parts[4]
                    schedule_time = parts[5]
                    capacity = int(parts[6])
                    duration = int(parts[7])
                    classes.append({
                        'class_id': class_id,
                        'class_name': class_name,
                        'trainer_id': trainer_id,
                        'class_type': class_type,
                        'schedule_day': schedule_day,
                        'schedule_time': schedule_time,
                        'capacity': capacity,
                        'duration': duration
                    })
    except FileNotFoundError:
        pass
    return classes


def load_trainers():
    filename = os.path.join(DATA_DIR, 'trainers.txt')
    trainers = []
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 6:
                    trainer_id = int(parts[0])
                    name = parts[1]
                    specialty = parts[2]
                    certifications = parts[3].split(', ')
                    experience_years = int(parts[4])
                    bio = parts[5]
                    trainers.append({
                        'trainer_id': trainer_id,
                        'name': name,
                        'specialty': specialty,
                        'certifications': certifications,
                        'experience_years': experience_years,
                        'bio': bio
                    })
    except FileNotFoundError:
        pass
    return trainers


def load_bookings():
    filename = os.path.join(DATA_DIR, 'bookings.txt')
    bookings = []
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 7:
                    booking_id = int(parts[0])
                    member_name = parts[1]
                    trainer_id = int(parts[2])
                    booking_date = parts[3]
                    booking_time = parts[4]
                    duration_minutes = int(parts[5])
                    status = parts[6]
                    bookings.append({
                        'booking_id': booking_id,
                        'member_name': member_name,
                        'trainer_id': trainer_id,
                        'booking_date': booking_date,
                        'booking_time': booking_time,
                        'duration_minutes': duration_minutes,
                        'status': status
                    })
    except FileNotFoundError:
        pass
    return bookings


def save_booking(booking):
    filename = os.path.join(DATA_DIR, 'bookings.txt')
    bookings = load_bookings()
    max_id = max([b['booking_id'] for b in bookings], default=0)
    new_id = max_id + 1
    try:
        with open(filename, 'a', encoding='utf-8') as f:
            line = f"{new_id}|{booking['member_name']}|{booking['trainer_id']}|{booking['booking_date']}|{booking['booking_time']}|{booking['duration_minutes']}|{booking['status']}\n"
            f.write(line)
            return new_id
    except Exception:
        return None


def load_workouts():
    filename = os.path.join(DATA_DIR, 'workouts.txt')
    workouts = []
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 7:
                    workout_id = int(parts[0])
                    member_name = parts[1]
                    workout_type = parts[2]
                    workout_date = parts[3]
                    duration_minutes = int(parts[4])
                    calories_burned = int(parts[5])
                    notes = parts[6]
                    workouts.append({
                        'workout_id': workout_id,
                        'member_name': member_name,
                        'workout_type': workout_type,
                        'workout_date': workout_date,
                        'duration_minutes': duration_minutes,
                        'calories_burned': calories_burned,
                        'notes': notes
                    })
    except FileNotFoundError:
        pass
    return workouts


def save_workout(workout):
    filename = os.path.join(DATA_DIR, 'workouts.txt')
    workouts = load_workouts()
    max_id = max([w['workout_id'] for w in workouts], default=0)
    new_id = max_id + 1
    try:
        with open(filename, 'a', encoding='utf-8') as f:
            line = f"{new_id}|{workout['member_name']}|{workout['workout_type']}|{workout['workout_date']}|{workout['duration_minutes']}|{workout['calories_burned']}|{workout['notes']}\n"
            f.write(line)
            return new_id
    except Exception:
        return None


# Root Route redirects to dashboard
@app.route('/')
def root_redirect():
    return redirect(url_for('dashboard'))

# Dashboard Page
@app.route('/dashboard', methods=['GET'])
def dashboard():
    # Member welcome/status message
    member_status = "Welcome to Gym Membership Dashboard!"

    membership_plans_all = load_memberships()
    membership_plans = []
    for plan in membership_plans_all:
        membership_plans.append({
            'membership_id': plan['membership_id'],
            'plan_name': plan['plan_name'],
            'price': plan['price'],
            'billing_cycle': plan['billing_cycle']
        })

    featured_classes = load_classes()[:3]  # Show first 3 as featured
    trainers = load_trainers()[:4]  # Quick access first 4 trainers

    return render_template('dashboard.html',
                           member_status=member_status,
                           membership_plans=membership_plans,
                           featured_classes=featured_classes,
                           trainers=trainers)

# Membership Plans Page
@app.route('/memberships', methods=['GET'])
def membership_plans_page():
    membership_plans = load_memberships()
    filter_types = list(set(mp['plan_name'] for mp in membership_plans))
    filter_types.sort()

    return render_template('memberships.html', membership_plans=membership_plans, filter_types=filter_types)

# Plan Details Page
@app.route('/plan/<int:plan_id>', methods=['GET'])
def plan_details_page(plan_id):
    membership_plans = load_memberships()
    plan = next((p for p in membership_plans if p['membership_id'] == plan_id), None)

    # No review data source given, passing empty list
    reviews = []

    return render_template('plan_details.html', plan=plan, reviews=reviews)

# Class Schedule Page
@app.route('/schedule', methods=['GET'])
def class_schedule_page():
    classes = load_classes()
    class_types = sorted(set(c['class_type'] for c in classes))
    search_query = request.args.get('search_query', '')
    return render_template('schedule.html', classes=classes, class_types=class_types, search_query=search_query)

# Trainer Profiles Page
@app.route('/trainers', methods=['GET'])
def trainers_page():
    trainers = load_trainers()
    specialties = sorted(set(t['specialty'] for t in trainers))
    search_query = request.args.get('search_query', '')
    return render_template('trainers.html', trainers=trainers, specialties=specialties, search_query=search_query)

# Trainer Detail Page
@app.route('/trainer/<int:trainer_id>', methods=['GET'])
def trainer_detail_page(trainer_id):
    trainers = load_trainers()
    trainer = next((t for t in trainers if t['trainer_id'] == trainer_id), None)

    # No reviews data source given
    reviews = []

    return render_template('trainer_detail.html', trainer=trainer, reviews=reviews)

