def load_memberships():
    memberships = []
    path = os.path.join(DATA_DIR, 'memberships.txt')
    try:
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 6:
                    membership_id = int(parts[0])
                    plan_name = parts[1]
                    price = float(parts[2])
                    billing_cycle = parts[3]
                    features = parts[4].split(', ')
                    max_classes_raw = parts[5]
                    if max_classes_raw.isdigit():
                        max_classes = int(max_classes_raw)
                    else:
                        max_classes = max_classes_raw
                    memberships.append({
                        'membership_id': membership_id,
                        'plan_name': plan_name,
                        'price': price,
                        'billing_cycle': billing_cycle,
                        'features': features,
                        'max_classes': max_classes
                    })
    except FileNotFoundError:
        pass
    return memberships


